import { useState, useEffect } from "react";
import axios from "axios";
import LoginPage from "./pages/LoginPage";
import SignupPage from "./pages/SignupPage";
import ChatPage from "./pages/ChatPage";

function App() {
  const [user, setUser] = useState(null);
  const [page, setPage] = useState("login");

  useEffect(() => {
    if ("serviceWorker" in navigator && "PushManager" in window) {
      navigator.serviceWorker.ready.then(reg => {
        return reg.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: urlBase64ToUint8Array(process.env.REACT_APP_VAPID_PUBLIC_KEY)
        });
      }).then(subscription => {
        console.log("Push subscription:", subscription);
        // Replace with the logged-in user's email/phone
        fetch("http://localhost:5001/user/saveSubscription", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ email: "b", subscription })
        });
      });
    }
  }, []);


  return page === "signup" ? (
    <SignupPage setUser={setUser} setPage={setPage} />
  ) : page === "login" ? (
    <LoginPage setUser={setUser} setPage={setPage} />
  ) : (
    <ChatPage user={user} />
  );
}

export default App;
